(function () {
  'use strict';

  // ─── ثوابت داخلية ───────────────────────────────────────────────
  const SUPPORTED_LANGS = Object.freeze(['en', 'ar', 'fr', 'es', 'de', 'it']);
  const SUPPORTED_SIZES = Object.freeze(['standard', 'minimal', 'wide']);
  const LABELS = Object.freeze({
    en: 'Protected by AntiBot',
    ar: 'محمي بواسطة AntiBot',
    fr: 'Protégé par AntiBot',
    es: 'Protegido por AntiBot',
    de: 'Geschützt durch AntiBot',
    it: 'Protetto da AntiBot',
  });

  // ─── أداة تنظيف المدخلات ─────────────────────────────────────────
  function sanitizeString(val, maxLen) {
    if (typeof val !== 'string') return '';
    return val.replace(/[<>"'`]/g, '').trim().slice(0, maxLen);
  }

  // ─── التحقق من صحة الـ URL ────────────────────────────────────────
  function isValidHttpUrl(str) {
    try {
      const url = new URL(str);
      return url.protocol === 'https:' || url.protocol === 'http:';
    } catch {
      return false;
    }
  }

  // ─── التحقق من صحة اللون HEX / CSS ──────────────────────────────
  function isValidColor(val) {
    return /^#[0-9A-Fa-f]{3,8}$/.test(val) ||
      /^(rgb|hsl)a?\([^)]{5,60}\)$/i.test(val);
  }

  // ─── قراءة الخصائص من الـ widget element ─────────────────────────
  function getConfig(el) {
    const rawUserId = el.getAttribute('data-user') || '';
    const rawColor  = el.getAttribute('data-color') || '#6366f1';
    const rawLang   = el.getAttribute('data-lang')  || 'en';
    const rawSize   = el.getAttribute('data-size')  || 'standard';
    const rawApi    = el.getAttribute('data-api-base') || window.location.origin;

    const userId = sanitizeString(rawUserId, 128);
    const color  = isValidColor(rawColor) ? rawColor : '#6366f1';
    const lang   = SUPPORTED_LANGS.includes(rawLang) ? rawLang : 'en';
    const size   = SUPPORTED_SIZES.includes(rawSize)  ? rawSize  : 'standard';
    const apiBase = isValidHttpUrl(rawApi) ? rawApi.replace(/\/+$/, '') : window.location.origin;

    return Object.freeze({ userId, color, lang, size, apiBase });
  }

  // ─── بناء أيقونة SVG بدون innerHTML ──────────────────────────────
  function buildShieldIcon(color) {
    const NS = 'http://www.w3.org/2000/svg';
    const svg = document.createElementNS(NS, 'svg');
    svg.setAttribute('width', '18');
    svg.setAttribute('height', '18');
    svg.setAttribute('viewBox', '0 0 24 24');
    svg.setAttribute('fill', 'none');
    svg.setAttribute('stroke', color);
    svg.setAttribute('stroke-width', '2');
    svg.setAttribute('stroke-linecap', 'round');
    svg.setAttribute('stroke-linejoin', 'round');
    svg.setAttribute('aria-hidden', 'true');

    const path = document.createElementNS(NS, 'path');
    path.setAttribute('d', 'M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z');
    svg.appendChild(path);
    return svg;
  }

  // ─── بناء مؤشر النبض ─────────────────────────────────────────────
  function buildPulse() {
    const pulse = document.createElement('span');
    pulse.setAttribute('aria-hidden', 'true');
    pulse.className = '__ab-pulse';
    return pulse;
  }

  // ─── حقن CSS مرة واحدة فقط ──────────────────────────────────────
  const STYLE_ID = '__ab-styles';
  function injectStyles(color) {
    if (document.getElementById(STYLE_ID)) return;
    const st = document.createElement('style');
    st.id = STYLE_ID;
    // نستخدم CSS variables لتجنب حقن قيم مباشرة
    st.textContent = [
      ':root { --ab-color: ' + color + '; }',
      '@keyframes __ab-pulse {',
      '  0%   { opacity: .4; transform: scale(1);   }',
      '  50%  { opacity: 1;  transform: scale(1.25);}',
      '  100% { opacity: .4; transform: scale(1);   }',
      '}',
      '.__ab-btn {',
      '  display: inline-flex;',
      '  align-items: center;',
      '  gap: 8px;',
      '  border-radius: 12px;',
      '  border: 2px solid var(--ab-color);',
      '  color: var(--ab-color);',
      '  font-size: 14px;',
      '  font-weight: 700;',
      '  font-family: "Segoe UI", system-ui, sans-serif;',
      '  background: transparent;',
      '  cursor: pointer;',
      '  transition: box-shadow .25s ease, opacity .25s ease;',
      '  user-select: none;',
      '  -webkit-user-select: none;',
      '}',
      '.__ab-btn:hover { box-shadow: 0 0 0 4px color-mix(in srgb, var(--ab-color) 20%, transparent); }',
      '.__ab-btn:focus-visible {',
      '  outline: 3px solid var(--ab-color);',
      '  outline-offset: 3px;',
      '}',
      '.__ab-btn[data-size="standard"] { padding: 10px 16px; }',
      '.__ab-btn[data-size="minimal"]  { padding: 8px; }',
      '.__ab-btn[data-size="wide"]     { padding: 10px 16px; width: 100%; justify-content: center; }',
      '.__ab-pulse {',
      '  display: inline-block;',
      '  width: 6px;',
      '  height: 6px;',
      '  border-radius: 50%;',
      '  background: #10b981;',
      '  animation: __ab-pulse 2s infinite;',
      '}',
    ].join('\n');
    document.head.appendChild(st);
  }

  // ─── إرسال الأحداث بأمان ─────────────────────────────────────────
  let lastClickTime = 0;
  const DEBOUNCE_MS = 1000; // منع النقر المتكرر

  function sendEvent(cfg, eventName) {
    if (!['impression', 'click'].includes(eventName)) return; // whitelist

    const endpoint = cfg.apiBase + '/api/widget/' + eventName;

    // تحقق مزدوج من الـ URL النهائي
    if (!isValidHttpUrl(endpoint)) return;

    const payload = JSON.stringify({
      user_id: cfg.userId,
      lang:    cfg.lang,
      size:    cfg.size,
    });

    try {
      fetch(endpoint, {
        method:  'POST',
        headers: {
          'Content-Type': 'application/json',
          'Accept':       'application/json',
        },
        body:        payload,
        mode:        'cors',
        credentials: 'omit',          // لا إرسال cookies
        referrerPolicy: 'no-referrer', // لا تسريب Referer
        cache:       'no-store',
      }).catch(function () { /* فشل صامت */ });
    } catch (_) { /* فشل صامت */ }
  }

  // ─── نقطة الدخول الرئيسية ────────────────────────────────────────
  function init() {
    const widget = document.getElementById('antibot-widget');
    if (!widget) return;

    const cfg = getConfig(widget);

    // تسجيل CSS variable للون
    injectStyles(cfg.color);

    // بناء الزر
    const btn = document.createElement('button');
    btn.className      = '__ab-btn';
    btn.type           = 'button';
    btn.setAttribute('data-size', cfg.size);
    btn.setAttribute('aria-label', LABELS[cfg.lang]);
    btn.setAttribute('role', 'link'); // يفتح رابطاً خارجياً

    // أيقونة SVG آمنة (بدون innerHTML)
    btn.appendChild(buildShieldIcon(cfg.color));

    // النص (بدون innerHTML)
    if (cfg.size !== 'minimal') {
      const label = document.createElement('span');
      label.textContent = LABELS[cfg.lang]; // textContent آمن دائماً
      btn.appendChild(label);
    }

    // مؤشر النبض
    btn.appendChild(buildPulse());

    widget.appendChild(btn);

    // إرسال impression
    sendEvent(cfg, 'impression');

    // معالج النقر مع debounce
    btn.addEventListener('click', function () {
      const now = Date.now();
      if (now - lastClickTime < DEBOUNCE_MS) return;
      lastClickTime = now;

      sendEvent(cfg, 'click');

      // فتح الرابط بأمان
      const win = window.open('about:blank', '_blank', 'noopener,noreferrer');
      if (win) {
        win.location.href = cfg.apiBase;
      }
    });
  }

  // ─── تشغيل عند جاهزية الـ DOM ────────────────────────────────────
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init, { once: true });
  } else {
    init();
  }

})();
